INSERT INTO `email_templates` (`id`, `date_entered`, `date_modified`, `modified_user_id`, `created_by`, `published`, `name`, `description`, `subject`, `body`, `body_html`, `deleted`, `assigned_user_id`, `text_only`, `type`) VALUES
('d3b49c38-eeba-b910-2590-5b4069caaac1', NOW(), NOW(), '1', '1', NULL, 'Example - Donation', 'Email template example for donation confirmation and acknowledgement', 'Thank you for your donation!', 'Dear $contact_first_name $contact_last_name,\r\n\r\nWe have successfully received your donation of $stic_payments_amount €.\r\n\r\nThank you very much for your support!\r\n\r\n', '<p>Dear $contact_first_name $contact_last_name,</p>\n<p>We have successfully received your donation of $stic_payments_amount €.</p>\n<p>Thank you for your support!</p>', 0, '1', 0, 'email'),
('dba65685-d26f-6ecd-802c-5b406983c9b5', NOW(), NOW(), '1', '1', NULL, 'Example - Registration', 'Email template example for registration confirmation', 'Registration confirmation to $stic_events_name', 'Dear $contact_first_name $contact_last_name,\r\n\r\nWe have successfully received your registration to $stic_events_name.\r\n\r\nOn $stic_registrations_registration_date your registration is $stic_registrations_status.\r\n\r\nSee you on $stic_events_start_date!', '<p>Dear $contact_first_name $contact_last_name,</p>\n<p>We have successfully received your registration to $stic_events_name.</p>\n<p>On $stic_registrations_registration_date your registration is $stic_registrations_status.</p>\n<p>See you on $stic_events_start_date!</p>', 0, '1', 0, 'email'),
('52cdc554-bd90-f8f9-e2e0-66d718ae8fe9', NOW(), NOW(), '1', '1', NULL, 'Example - New opportunity', 'Email template example for new opportunity notification', 'New opportunity: $opportunity_name', 'New opportunity: $opportunity_name\r\n\r\n$opportunity_stic_additional_information_c\r\nYou may find more information at: $opportunity_stic_opportunity_url_c', '<p>New opportunity: $opportunity_name</p><p></p><p>$opportunity_stic_additional_information_c</p><p>You may find more information at: $opportunity_stic_opportunity_url_c</p>', 0, '1', 0, 'notification'),
('9f118e85-13f2-baa9-4ee3-66d80c674dea', NOW(), NOW(), '1', '1', NULL, 'Example - New event', 'Email template example for new event notification', 'New event: $stic_events_name', '$stic_events_name\r\n\r\nStart date: $stic_events_start_date\r\nEnd date: $stic_events_end_date\r\nLocation: $stic_events_stic_events_fp_event_locations_name', '<p>$stic_events_name</p><p></p><p>Start date: $stic_events_start_date</p><p>End date: $stic_events_end_date</p><p>Location: $stic_events_stic_events_fp_event_locations_name</p>', 0, '1', 0, 'notification'),
('000005f1-2e4e-3b11-051f-68e3c9e70330', NOW(), NOW(), '1', '1', 'off', 'Example - Signature request', 'Template to notify the signer that their signature in a document has been requested.', '[Document signature] Request of signature: $stic_signatures_pdf_template', 'Request of signature\n\nYour signature has been requested in the following document:\n\n$stic_signatures_pdf_template\n\nSigner: $contact_full_name$contact_user_full_name\nExpiration date: $stic_signatures_expiration_date\n\nTo sign the document, please click below and you will be redirected to the secure signing portal.\n\nSign the document: $sugarurl/index.php?entryPoint=sticSign&signatureId=$stic_signatures_id&targetId=$contact_id$contact_user_id\n\nIf you have trouble accessing the signing portal, please copy and paste the link into your browser:\n$sugarurl/index.php?entryPoint=sticSign&signatureId=$stic_signatures_id&targetId=$contact_id$contact_user_id', '<!DOCTYPE html>\n<html>\n<head>\n</head>\n<body>\n<p> </p>\n<div style="max-width: 600px; margin: 20px auto; background-color: #ffffff; border-radius: 8px; box-shadow: 0 4px 8px rgba(0,0,0,0.1); overflow: hidden;">\n<div style="background-color: #b5bc31; color: #000000; padding: 20px; text-align: center;">\n<h1 style="margin: 0; font-size: 24px;">Document Signature</h1>\n</div>\n<div style="padding: 20px;">\n<p style="font-size: 16px; color: #555555;">Your signature has been requested on the following document:</p>\n<div style="background-color: #f9f9f9; padding: 15px; border-radius: 6px; border: 1px solid #eeeeee; margin-top: 20px;">\n<p style="margin: 0; font-size: 16px; color: #333333;"><strong>$stic_signatures_pdf_template</strong></p>\n<p style="margin: 5px 0 0 0; font-size: 14px; color: #888888;"><strong>Signer:</strong> $contact_full_name$contact_user_full_name</p>\n<p style="margin: 5px 0 0 0; font-size: 14px; color: #888888;"><strong>Expiration date:</strong> $stic_signatures_expiration_date</p>\n</div>\n<p style="font-size: 16px; color: #555555; margin-top: 20px;">To sign the document, please click below and you will be redirected to the secure signing portal.</p>\n<p style="font-size: 16px; color: #555555; margin-top: 20px;"> </p>\n<div style="text-align: center; margin-top: 30px;"><a style="display: inline-block; padding: 12px 24px; font-size: 16px; color: #000000; background-color: #b5bc31; border-radius: 5px; text-decoration: none; font-weight: bold;" href="$sugarurl/index.php?entryPoint=sticSign&signatureId=$stic_signatures_id&targetId=$contact_id$contact_user_id">Sign Document</a></div>\n<p style="font-size: 14px; color: #aaaaaa; text-align: center; margin-top: 30px;">If you have trouble accessing the signing portal, please copy and paste the link into your browser: <br /><a style="color: #b5bc31; text-decoration: none;" href="$sugarurl/index.php?entryPoint=sticSign&signatureId=$stic_signatures_id&targetId=$contact_id$contact_user_id">$sugarurl/index.php?entryPoint=sticSign&signatureId=$stic_signatures_id&targetId=$contact_id$contact_user_id</a></p>\n</div>\n</div>\n</body>\n</html>', 0, '1', 0, 'notification'),
('000005f1-2e4e-3b11-051f-68e3c9e70331', NOW(), NOW(), '1', '1', 'off', 'Example - Signed document', 'Template to send the signed document to the signer.', '[Document signature] Signed document: $stic_signatures_pdf_template', 'Signed document\n\nAttached you will find the final version of the document you have signed:\n\n$stic_signatures_pdf_template\n\nSigner: $contact_full_name$contact_user_full_name\nDate of signature: $stic_signers_signature_date\n\nYou may access the signed document on the signing portal whenever necessary.\n\nGo to the signing portal: $sugarurl/index.php?entryPoint=sticSign&signerId=$stic_signers_id', '<!DOCTYPE html>\n<html>\n<head>\n</head>\n<body>\n<p> </p>\n<div style="max-width: 600px; margin: 20px auto; background-color: #ffffff; border-radius: 8px; box-shadow: 0 4px 8px rgba(0,0,0,0.1); overflow: hidden;">\n<div style="background-color: #b5bc31; color: #000000; padding: 20px; text-align: center;">\n<h1 style="margin: 0; font-size: 24px;">Signed document</h1>\n</div>\n<div style="padding: 20px;">\n<p style="font-size: 16px; color: #555555;">Attached to this email you will find the final version of the document you have signed:</p>\n<div style="background-color: #f9f9f9; padding: 15px; border-radius: 6px; border: 1px solid #eeeeee; margin-top: 20px;">\n<p style="margin: 0; font-size: 16px; color: #333333;"><strong>$stic_signatures_pdf_template</strong></p>\n<p style="margin: 5px 0 0 0; font-size: 14px; color: #888888;"><strong>Signer:</strong> $contact_full_name$contact_user_full_name</p>\n<p style="margin: 5px 0 0 0; font-size: 14px; color: #888888;"><strong>Date of signature:</strong> $stic_signers_signature_date</p>\n</div>\n<p style="font-size: 16px; color: #555555; margin-top: 20px;">You may access the signed document on the signing portal whenever necessary.</p>\n<div style="text-align: center; margin-top: 30px;"><a style="display: inline-block; padding: 12px 24px; font-size: 16px; color: #000000; background-color: #b5bc31; border-radius: 5px; text-decoration: none; font-weight: bold;" href="$sugarurl/index.php?entryPoint=sticSign&signerId=$stic_signers_id">Go to the signing portal</a></div>\n</div>\n</div>\n</body>\n</html>', 0, '1', 0, 'notification'),
('000005f1-2e4e-3b11-051f-68e3c9e70332', NOW(), NOW(), '1', '1', 'off', 'Example - One time code for signing', 'Template to send the one time code to the signer before signing.', '[Document signature] Verification code for signing', 'Signature verification\n\nTo ensure the security and authenticity of your signature, please use the verification code shown below:\n\n$stic_signatures_pdf_template\n\n$stic_signers_otp\n\nPlease enter this code in the signing portal to proceed. The code is valid for 10 minutes and it can only be used once.', '<!DOCTYPE html>\n<html>\n<head>\n</head>\n<body>\n<p> </p>\n<div style="max-width: 600px; margin: 20px auto; background-color: #ffffff; border-radius: 8px; box-shadow: 0 4px 8px rgba(0,0,0,0.1); overflow: hidden;">\n<div style="background-color: #b5bc31; color: #000000; padding: 20px; text-align: center;">\n<h1 style="margin: 0; font-size: 24px;">Signature verification</h1>\n</div>\n<div style="padding: 20px;">\n<p style="font-size: 16px; color: #555555;">To ensure the security and authenticity of your signature, please use the verification code shown below:</p>\n<div style="background-color: #f9f9f9; padding: 15px; border-radius: 6px; border: 1px solid #eeeeee; margin-top: 20px;">\n<p style="margin: 0; font-size: 16px; color: #333333;"><strong>$stic_signatures_pdf_template</strong></p>\n<div style="text-align: center; margin-top: 10px; margin-bottom: 10px;"><span style="display: inline-block; padding: 15px 30px; font-size: 28px; color: #000000; background-color: #b5bc31; border-radius: 5px; font-weight: bold; letter-spacing: 5px;">$stic_signers_otp</span></div>\n</div>\n<p style="font-size: 16px; color: #555555; margin-top: 20px;">Please enter this code in the signing portal to proceed. The code is valid for 10 minutes and can only be used once.</span></p>\n</div>\n</div>\n</body>\n</html>', 0, '1', 0, 'notification'),
('000005f1-2e4e-3b11-051f-68e3c9e70333', NOW(), NOW(), '1', '1', 'off', 'Example - One time code for signing (SMS)', 'Template to send by SMS the one time code to the signer before signing.', '[Document signature] Verification code for signing', '$contact_first_name$contact_user_first_name, this is your code for signing: $stic_signers_otp. It is valid for 10 minutes.', '<!DOCTYPE html>\n<html>\n<head>\n</head>\n<body>\n\n</body>\n</html>', 0, '1', 1, 'system'),
('00000b6d-9a8d-37c0-684e-6931622133d8', NOW(), NOW(), '1', '1', 'off', 'Example - Insurance policy renewal notification', NULL, 'Renewal of the volunteer insurance policy', NULL, '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n</head>\r\n<body>\r\n<p>$contact_name’s <strong>volunteer insurance policy</strong> is about to expire and requires renewal to maintain active coverage.</p>\r\n</body>\r\n</html>', 0, '1', 0, 'email'),
('00000258-e3da-390c-e722-693162f2060f', NOW(), NOW(), '1', '1', 'off', 'Example - Notification of the renewal of the criminal record certificate', NULL, 'Renewal of the criminal record certificate', NULL, '<!DOCTYPE html>\r\n<html>\r\n<head>\r\n</head>\r\n<body>\r\n<p>$contact_name’s <strong>crime certificate</strong> is about to expire and needs to be renewed in order for him/her to continue working in the organization.</p>\r\n</body>\r\n</html>', 0, '1', 0, 'email'),
('d3c1d5b7-f8d2-4df4-9f6b-2c63aa6b8e41', NOW(), NOW(), '1', '1', NULL, 'Example - Notification - Offer with expired closing date and not closed status', 'Template to notify the responsible user that the offer has an application closing date of yesterday and is not in closed status or similar.', 'Review job offer: application deadline passed - $stic_job_offers_name', 'Dear $stic_job_offers_assigned_user_name,\r\n\r\nThe job offer $stic_job_offers_name has an expired application closing date (yesterday) and is currently in status $stic_job_offers_status.\r\n\r\nPlease review the offer and update its status if appropriate: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Dear $stic_job_offers_assigned_user_name,</p>\n<p>The job offer <strong>$stic_job_offers_name</strong> has an expired application closing date (yesterday) and is currently in status <strong>$stic_job_offers_status</strong>.</p>\n<p>Please <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">review the offer</a> and update its status if appropriate.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0001', NOW(), NOW(), '1', '1', NULL, 'Example - Accepted application - Assigned user ', 'Notifies the assigned user when an application changes to Accepted, with a CRM link.', 'Accepted application: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_assigned_user_name,\r\n\r\nThe application of $stic_job_applications_stic_job_applications_contacts_name for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to Accepted status.\r\n\r\nYou can review it in the CRM: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Dear $stic_job_applications_assigned_user_name,</p><p>The application of <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to <strong>Accepted</strong> status.</p><p>You can review it in the CRM: <a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Open application in CRM</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0002', NOW(), NOW(), '1', '1', NULL, 'Example - Accepted application - Candidate ', 'Notifies the candidate when their application changes to Accepted, with a private area link.', 'Your application has been accepted: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_stic_job_applications_contacts_name:\r\n\r\nWe are pleased to inform you that your application for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to Accepted status.\r\n\r\nYou can view the details in your private area: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Dear $stic_job_applications_stic_job_applications_contacts_name:</p><p>We are pleased to inform you that your application for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to <strong>Accepted</strong> status.</p><p>You can view the details in your private area: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Access private area</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0003', NOW(), NOW(), '1', '1', NULL, 'Example - Accepted application - Organization ', 'Notifies the organization when an application changes to Accepted, with a private area link.', 'Accepted application in offer: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_account,\r\n\r\nThe application of $stic_job_applications_stic_job_applications_contacts_name for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to Accepted status.\r\n\r\nYou can view it in the private area: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Dear $stic_job_applications_account,</p><p>The application of <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to <strong>Accepted</strong> status.</p><p>You can view it in the private area: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Access private area</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0013', NOW(), NOW(), '1', '1', NULL, 'Example - Application rejected/closed - Assigned User', 'Notifies the assigned user.', 'Application rejected or closed: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_assigned_user_name,\n\nWe inform you that the status for $stic_job_applications_stic_job_applications_contacts_name regarding the position $stic_job_applications_stic_job_applications_stic_job_offers_name has been updated.\n\nNew status: Application rejected / Process closed.', '<p>Dear <strong>$stic_job_applications_assigned_user_name</strong>,</p><p>We inform you that the status for <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> regarding the position <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has been updated.</p><p>New status: <strong>Application rejected / Process closed.</strong></p><p>You can review the details in the CRM: <a href=\"$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id\">Open application in CRM</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0014', NOW(), NOW(), '1', '1', NULL, 'Example - Application rejected/closed - Candidate', 'Formal rejection notice.', 'Update on your application: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_stic_job_applications_contacts_name:\n\nThank you for your interest in $stic_job_applications_stic_job_applications_stic_job_offers_name.\n\nAfter careful consideration, we regret to inform you that we have decided to move forward with other candidates.', '<p>Dear <strong>$stic_job_applications_stic_job_applications_contacts_name</strong>:</p><p>Thank you very much for your interest in the <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> position.</p><p>After careful consideration, we regret to inform you that we have decided to move forward with other candidates whose profiles more closely match our requirements.</p><p>You can check your status in your private area: <a href=\"$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id\">Access Private Area</a>.</p><p>Best regards,<br><strong>$stic_job_applications_account</strong></p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0015', NOW(), NOW(), '1', '1', NULL, 'Example - Application rejected/closed - Organization', 'Notifies the account.', 'Application rejected or closed for: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_account:\n\nWe inform you that the application for $stic_job_applications_stic_job_applications_contacts_name regarding $stic_job_applications_stic_job_applications_stic_job_offers_name has concluded.', '<p>Dear <strong>$stic_job_applications_account</strong>:</p><p>We inform you that the application of <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> for the position <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has concluded its participation in the process.</p><p>You can track the details in your client area: <a href=\"$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id\">Access Private Area</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0007', NOW(), NOW(), '1', '1', NULL, 'Example - Other application statuses - Assigned user ', 'Notifies the assigned user when an application changes to other statuses, with a CRM link.', 'Application status changed: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_assigned_user_name,\r\n\r\nThe application of $stic_job_applications_stic_job_applications_contacts_name for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to status $stic_job_applications_status.\r\n\r\nYou can access details at: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Dear $stic_job_applications_assigned_user_name,</p><p>The application of <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to status <strong>$stic_job_applications_status</strong>.</p><p>You can access details at: <a href="$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id">Open application in CRM</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0008', NOW(), NOW(), '1', '1', NULL, 'Example - Other application statuses - Candidate ', 'Notifies the candidate when their application changes to other statuses, with a private area link.', 'Your application status changed: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_stic_job_applications_contacts_name:\r\n\r\nYour application for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to status $stic_job_applications_status.\r\n\r\nYou can view the details in your private area: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Dear $stic_job_applications_stic_job_applications_contacts_name:</p><p>Your application for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to status <strong>$stic_job_applications_status</strong>.</p><p>You can view the details in your private area: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Access private area</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0009', NOW(), NOW(), '1', '1', NULL, 'Example - Other application statuses - Organization ', 'Notifies the organization when an application changes to other statuses, with a private area link.', 'Application status changed in offer: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_account,\r\n\r\nThe application of $stic_job_applications_stic_job_applications_contacts_name for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name has changed to status $stic_job_applications_status.\r\n\r\nYou can view it in the private area: $portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id', '<p>Dear $stic_job_applications_account,</p><p>The application of <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> has changed to status <strong>$stic_job_applications_status</strong>.</p><p>You can view it in the private area: <a href="$portal_address/?internalpage=single_stic_job_applications&action=detail&id=$stic_job_applications_id">Access private area</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0010', NOW(), NOW(), '1', '1', NULL, 'Example - Offer status change - Assigned user ', 'Notifies the assigned user when an offer status changes, with a CRM link.', 'Offer status changed: $stic_job_offers_name', 'Dear $stic_job_offers_assigned_user_name,\r\n\r\nThe offer $stic_job_offers_name has changed to status $stic_job_offers_status.\r\n\r\nYou can access details at: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Dear $stic_job_offers_assigned_user_name,</p><p>The offer <strong>$stic_job_offers_name</strong> has changed to status <strong>$stic_job_offers_status</strong>.</p><p>You can access details at: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Open offer in CRM</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0011', NOW(), NOW(), '1', '1', NULL, 'Example - Offer status change - Candidates ', 'Notifies candidates of an offer status change, with a private area link.', 'Offer update: $stic_job_offers_name', 'Dear,\r\n\r\nThe offer $stic_job_offers_name has changed to status $stic_job_offers_status.\r\n\r\nYou can view the offer in the private area: $portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id', '<p>Dear,</p><p>The offer <strong>$stic_job_offers_name</strong> has changed to status <strong>$stic_job_offers_status</strong>.</p><p>You can view the offer in the private area: <a href="$portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id">View offer in private area</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0012', NOW(), NOW(), '1', '1', NULL, 'Example - Offer status change - Organization ', 'Notifies the organization of an offer status change, with a private area link.', 'Offer status changed: $stic_job_offers_name', 'Dear $stic_job_offers_stic_job_offers_accounts_name,\r\n\r\nThe offer $stic_job_offers_name has changed to status $stic_job_offers_status.\r\n\r\nYou can review it in the private area: $portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id', '<p>Dear $stic_job_offers_stic_job_offers_accounts_name,</p><p>The offer <strong>$stic_job_offers_name</strong> has changed to status <strong>$stic_job_offers_status</strong>.</p><p>You can review it in the private area: <a href="$portal_address/?internalpage=single_stic_job_offers&action=detail&id=$stic_job_offers_id">View offer in private area</a>.</p>', 0, '1', 0, 'notification'),
('1a2d6f10-8e32-4f8a-9a11-3b1b7c2a0013', NOW(), NOW(), '1', '1', NULL, 'Example - Offer status change - Interlocutor', 'Notifies the interlocutor when an offer status changes, with a CRM link.', 'Offer update: $stic_job_offers_name', 'Dear $stic_job_offers_interlocutor,\r\n\r\nThe offer $stic_job_offers_name has changed to status $stic_job_offers_status.\r\n\r\nYou can review it in the CRM: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Dear $stic_job_offers_interlocutor,</p><p>The offer <strong>$stic_job_offers_name</strong> has changed to status <strong>$stic_job_offers_status</strong>.</p><p>You can review it in the CRM: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Open offer in CRM</a>.</p>', 0, '1', 0, 'notification'),
('6e6f5a91-2cb9-4f42-bf26-0a13b2f1c101', NOW(), NOW(), '1', '1', NULL, 'Example - Private Area - Access credentials (Contact)', 'Initial template to send Private Area credentials to Contacts when access is enabled', 'Your Private Area access credentials', 'Hello $contacts_name,\r\n\r\nYour access to the Private Area has been enabled.\r\n\r\nUsername: $contacts_stic_pa_username_c\r\nPassword: $contacts_stic_pa_password_c\r\n\r\nAccess from: $portal_address\r\n\r\nIf you did not request this access, please contact the organization.', '<p>Hello $contacts_name,</p><p>Your access to the Private Area has been enabled.</p><p><strong>Username:</strong> $contacts_stic_pa_username_c<br><strong>Password:</strong> $contacts_stic_pa_password_c</p><p>Access from: <a href="$portal_address">$portal_address</a></p><p>If you did not request this access, please contact the organization.</p>', 0, '1', 0, 'notification'),
('6e6f5a91-2cb9-4f42-bf26-0a13b2f1c102', NOW(), NOW(), '1', '1', NULL, 'Example - Private Area - Access credentials (Account)', 'Initial template to send Private Area credentials to Accounts when access is enabled', 'Private Area access credentials', 'Hello $accounts_name,\r\n\r\nYour access to the Private Area has been enabled.\r\n\r\nUsername: $accounts_stic_pa_username_c\r\nPassword: $accounts_stic_pa_password_c\r\n\r\nAccess from: $portal_address\r\n\r\nIf you did not request this access, please contact the organization.', '<p>Hello $accounts_name,</p><p>Your access to the Private Area has been enabled.</p><p><strong>Username:</strong> $accounts_stic_pa_username_c<br><strong>Password:</strong> $accounts_stic_pa_password_c</p><p>Access from: <a href="$portal_address">$portal_address</a></p><p>If you did not request this access, please contact the organization.</p>', 0, '1', 0, 'notification'),
('7a9f8f3a-2d1f-4a40-9dd6-7c6f9e1b7001', '2026-03-31 17:31:01', '2026-03-31 17:31:01', '1', '1', NULL, 'Example - Application submitted - Assigned user', 'Notifies the assigned user when a new application is submitted, with a CRM link.', 'New application received: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Dear $stic_job_applications_assigned_user_name,\r\n\r\nA new application from $stic_job_applications_stic_job_applications_contacts_name has been submitted for the offer $stic_job_applications_stic_job_applications_stic_job_offers_name.\r\n\r\nYou can review it in the CRM: $sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id', '<p>Dear $stic_job_applications_assigned_user_name,</p><p>A new application from <strong>$stic_job_applications_stic_job_applications_contacts_name</strong> has been submitted for the offer <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong>.</p><p>You can review it in the CRM: <a href=\"$sugarurl/index.php?module=stic_Job_Applications&action=DetailView&record=$stic_job_applications_id\">Open application in CRM</a>.</p>', 0, '1', 0, 'notification'),
('7a9f8f3a-2d1f-4a40-9dd6-7c6f9e1b7002', '2026-03-31 17:31:01', '2026-03-31 17:31:01', '1', '1', NULL, 'Example - New message in conversation - Assigned user', 'Notifies the assigned user when a new message arrives in a conversation.', 'New message received', 'Dear $stic_messages_assigned_user_name,\r\n\r\nA new message has been received in a portal conversation.\r\n\r\nMessage:\r\n$stic_messages_message\r\n\r\nYou can review it in the CRM: $sugarurl/index.php?module=stic_Messages&action=DetailView&record=$stic_messages_id', '<p>Dear $stic_messages_assigned_user_name,</p><p>A new message has been received in a portal conversation.</p><p><strong>Message:</strong><br>$stic_messages_message</p><p>You can review it in the CRM: <a href=\"$sugarurl/index.php?module=stic_Messages&action=DetailView&record=$stic_messages_id\">Open message in CRM</a>.</p>', 0, '1', 0, 'notification'),
('3c0a5f6e-1111-4f8a-9a11-3b1b7c2a0101', NOW(), NOW(), '1', '1', NULL, 'Example - New job offer - Assigned user', 'Notifies assigned user when a new job offer is created.', 'New offer created: $stic_job_offers_name', 'Dear $stic_job_offers_assigned_user_name,\r\n\r\nA new job offer has been created: $stic_job_offers_name.\r\n\r\nYou can review it in the CRM: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Dear $stic_job_offers_assigned_user_name,</p><p>A new job offer has been created: <strong>$stic_job_offers_name</strong>.</p><p>You can review it in the CRM: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Open offer in CRM</a>.</p>', 0, '1', 0, 'notification'),
('3c0a5f6e-1111-4f8a-9a11-3b1b7c2a0102', NOW(), NOW(), '1', '1', NULL, 'Example - New job offer - Organization', 'Notifies organization when a new job offer is created.', 'New offer created: $stic_job_offers_name', 'Dear $stic_job_offers_stic_job_offers_accounts_name,\r\n\r\nA new job offer has been created: $stic_job_offers_name.\r\n\r\nYou can review it in the CRM: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Dear $stic_job_offers_stic_job_offers_accounts_name,</p><p>A new job offer has been created: <strong>$stic_job_offers_name</strong>.</p><p>You can review it in the CRM: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Open offer in CRM</a>.</p>', 0, '1', 0, 'notification'),
('3c0a5f6e-1111-4f8a-9a11-3b1b7c2a0103', NOW(), NOW(), '1', '1', NULL, 'Example - New job offer - Interlocutor', 'Notifies interlocutor when a new job offer is created.', 'New offer created: $stic_job_offers_name', 'Dear $stic_job_offers_interlocutor,\r\n\r\nA new job offer has been created: $stic_job_offers_name.\r\n\r\nYou can review it in the CRM: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Dear $stic_job_offers_interlocutor,</p><p>A new job offer has been created: <strong>$stic_job_offers_name</strong>.</p><p>You can review it in the CRM: <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">Open offer in CRM</a>.</p>', 0, '1', 0, 'notification');
INSERT INTO `email_templates` (`id`, `date_entered`, `date_modified`, `modified_user_id`, `created_by`, `published`, `name`, `description`, `subject`, `body`, `body_html`, `deleted`, `assigned_user_id`, `text_only`, `type`) VALUES
('14f18ded-378d-ab84-3237-5e830d4e874d', NOW(), NOW(), '1', '1', 'off', 'User Case Update', 'Email template to send to a Sugar user when their case is updated.', '$acase_name (# $acase_case_number) update', 'Hi $user_first_name $user_last_name,\n\n					   You''ve had an update to your case $acase_name (# $acase_case_number) on $aop_case_updates_date_entered:\n					       $contact_first_name $contact_last_name, said:\n					               $aop_case_updates_description\n                        You may review this Case at:\n                            $sugarurl/index.php?module=Cases&action=DetailView&record=$acase_id;', '<p>Hi $user_first_name $user_last_name,</p>\n					     <p> </p>\n					     <p>You''ve had an update to your case $acase_name (# $acase_case_number) on $aop_case_updates_date_entered:</p>\n					     <p><strong>$contact_first_name $contact_last_name, said:</strong></p>\n					     <p style="padding-left:30px;">$aop_case_updates_description</p>\n					     <p>You may review this Case at: $sugarurl/index.php?module=Cases&action=DetailView&record=$acase_id;</p>', 0, NULL, NULL, 'system'),
('267275d8-959c-6aed-8754-5e830d07fedf', NOW(), NOW(), '1', '1', 'off', 'Event Invite Template', 'Default event invite template.', 'You have been invited to $fp_events_name', 'Dear $contact_name,\nYou have been invited to $fp_events_name on $fp_events_date_start to $fp_events_date_end\n$fp_events_description\nYours Sincerely,\n', '\n<p>Dear $contact_name,</p>\n<p>You have been invited to $fp_events_name on $fp_events_date_start to $fp_events_date_end</p>\n<p>$fp_events_description</p>\n<p>If you would like to accept this invititation please click accept.</p>\n<p> $fp_events_link or $fp_events_link_declined</p>\n<p>Yours Sincerely,</p>\n', 0, NULL, NULL, 'system'),
('483e1c3b-51dc-b5ab-e220-5e830d52596a', NOW(), NOW(), '1', '1', 'off', 'Confirmed Opt In', 'Email template to send to a contact to confirm they have opted in.', 'Confirm Opt In', 'Hi $contact_first_name $contact_last_name, \\n Please confirm that you have opted in by selecting the following link: $sugarurl/index.php?entryPoint=ConfirmOptIn&from=$emailaddress_email_address', '<p>Hi $contact_first_name $contact_last_name,</p>\n             <p>\n                Please confirm that you have opted in by selecting the following link:\n                <a href="$sugarurl/index.php?entryPoint=ConfirmOptIn&from=$emailaddress_confirm_opt_in_token">Opt In</a>\n             </p>', 0, NULL, NULL, 'system'),
('b4477938-f3c4-bef6-292c-5e830dee6ceb', NOW(), NOW(), '1', '1', 'off', 'System-generated password email', 'This template is used when the System Administrator sends a new password to a user.', 'New account information', '\nHere is your account username and temporary password:\nUsername : $contact_user_user_name\nPassword : $contact_user_user_hash\n\n$config_site_url\n\nAfter you log in using the above password, you may be required to reset the password to one of your own choice.', '<div><table width="550"><tbody><tr><td><p>Here is your account username and temporary password:</p><p>Username : $contact_user_user_name </p><p>Password : $contact_user_user_hash </p><br /><p>$config_site_url</p><br /><p>After you log in using the above password, you may be required to reset the password to one of your own choice.</p>   </td>         </tr><tr><td></td>         </tr></tbody></table></div>', 0, NULL, 0, 'system'),
('bc4c87c3-febd-73d5-cf73-5e830dd3bac0', NOW(), NOW(), '1', '1', 'off', 'Forgot Password email', 'This template is used to send a user a link to click to reset the user''s account password.', 'Reset your account password', '\nYou recently requested on $contact_user_pwd_last_changed to be able to reset your account password.\n\nClick on the link below to reset your password:\n\n$contact_user_link_guid', '<div><table width="550"><tbody><tr><td><p>You recently requested on $contact_user_pwd_last_changed to be able to reset your account password. </p><p>Click on the link below to reset your password:</p><p> $contact_user_link_guid </p>  </td>         </tr><tr><td></td>         </tr></tbody></table></div>', 0, NULL, 0, 'system'),
('c4440a38-10b9-ef63-0e40-5e830d1c293d', NOW(), NOW(), '1', '1', 'off', 'Two Factor Authentication email', 'This template is used to send a user a code for Two Factor Authentication.', 'Two Factor Authentication Code', 'Two Factor Authentication code is $code.', '<div><table width="550"><tbody><tr><td><p>Two Factor Authentication code is <b>$code</b>.</p>  </td>         </tr><tr><td></td>         </tr></tbody></table></div>', 0, NULL, 0, 'system'),
('c6c4093f-0a1a-30d8-5e33-5e830d6ddd51', NOW(), NOW(), '1', '1', 'off', 'Contact Case Update', 'Template to send to a contact when their case is updated.', '$acase_name update [CASE:$acase_case_number]', 'Hi $user_first_name $user_last_name,\n\n					   You''ve had an update to your case $acase_name (# $acase_case_number) on $aop_case_updates_date_entered:\n					       $contact_first_name $contact_last_name, said:\n					               $aop_case_updates_description', '<p>Hi $contact_first_name $contact_last_name,</p>\n					    <p> </p>\n					    <p>You''ve had an update to your case $acase_name (# $acase_case_number) on $aop_case_updates_date_entered:</p>\n					    <p><strong>$user_first_name $user_last_name said:</strong></p>\n					    <p style="padding-left:30px;">$aop_case_updates_description</p>', 0, NULL, NULL, 'system'),
('e61c85c2-e6cb-6dda-3760-5e830d31fbdc', NOW(), NOW(), '1', '1', 'off', 'Case Closure', 'Template for informing a contact that their case has been closed.', '$acase_name [CASE:$acase_case_number] closed', 'Hi $contact_first_name $contact_last_name,\n\n					   Your case $acase_name (# $acase_case_number) has been closed on $acase_date_entered\n					   Status:				$acase_status\n					   Reference:			$acase_case_number\n					   Resolution:			$acase_resolution', '<p> Hi $contact_first_name $contact_last_name,</p>\n					    <p>Your case $acase_name (# $acase_case_number) has been closed on $acase_date_entered</p>\n					    <table border="0"><tbody><tr><td>Status</td><td>$acase_status</td></tr><tr><td>Reference</td><td>$acase_case_number</td></tr><tr><td>Resolution</td><td>$acase_resolution</td></tr></tbody></table>', 0, NULL, NULL, 'system'),
('e9e00ea2-ac1b-a635-9671-5e830d66a582', NOW(), NOW(), '1', '1', 'off', 'Case Creation', 'Template to send to a contact when a case is received from them.', '$acase_name [CASE:$acase_case_number]', 'Hi $contact_first_name $contact_last_name,\n\n					   We''ve received your case $acase_name (# $acase_case_number) on $acase_date_entered\n					   Status:		$acase_status\n					   Reference:	$acase_case_number\n					   Description:	$acase_description', '<p> Hi $contact_first_name $contact_last_name,</p>\n					    <p>We''ve received your case $acase_name (# $acase_case_number) on $acase_date_entered</p>\n					    <table border="0"><tbody><tr><td>Status</td><td>$acase_status</td></tr><tr><td>Reference</td><td>$acase_case_number</td></tr><tr><td>Description</td><td>$acase_description</td></tr></tbody></table>', 0, NULL, NULL, 'system'),
('ed9867a2-1f56-b684-4bc6-5e830d215b5d', NOW(), NOW(), '1', '1', 'off', 'Joomla Account Creation', 'Template used when informing a contact that they''ve been given an account on the joomla portal.', 'Support Portal Account Created', 'Hi $contact_name,\n					   An account has been created for you at $portal_address.\n					   You may login using this email address and the password $joomla_pass', '<p>Hi $contact_name,</p>\n					    <p>An account has been created for you at <a href="$portal_address">$portal_address</a>.</p>\n					    <p>You may login using this email address and the password $joomla_pass</p>', 0, NULL, NULL, 'system');
